import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

const val BASE_URL_DEV = "https://dev.example.com/users"
const val BASE_URL_STAGING = "https://staging.example.com/users"
const val BASE_URL_PROD = "https://api.example.com/users"

fun getRetrofit(baseUrl: String): Retrofit {
    val loggingInterceptor = HttpLoggingInterceptor()
    loggingInterceptor.level = HttpLoggingInterceptor.Level.BODY

    val client = OkHttpClient.Builder()
        .addInterceptor(loggingInterceptor)
        .build()

    return Retrofit.Builder()
        .baseUrl(baseUrl)
        .client(client)
        .addConverterFactory(GsonConverterFactory.create())
        .build()
}

fun getUserProfile(token: String, userId: String): Call<UserProfile> {
    val retrofit = getRetrofit(BASE_URL_PROD)
    val apiService = retrofit.create(ApiService::class.java)

    return apiService.getUserProfile(token, userId)
}

interface ApiService {
    @GET("/{userId}")
    fun getUserProfile(@Header("Authorization") token: String, @Path("userId") userId: String): Call<UserProfile>
}

data class UserProfile(val id: Int, val name: String, val email: String)